import { Text as PDFText, View } from '@react-pdf/renderer';
import type { Style } from '@react-pdf/types';
import { usePdfxTheme, useSafeMemo } from '../lib/pdfx-theme-context';
import { createPageNumberStyles } from './pdfx-page-number.styles';
import type { PageNumberAlign, PageNumberSize, PdfPageNumberProps } from './pdfx-page-number.types';

/**
 * Formats the page number string by replacing placeholders.
 * @param format - Format string with {page} and {total} placeholders
 * @param pageNumber - Current page number
 * @param totalPages - Total number of pages
 */
function formatPageNumber(format: string, pageNumber: number, totalPages: number): string {
  return format.replace('{page}', String(pageNumber)).replace('{total}', String(totalPages));
}

/**
 * PdfPageNumber — Displays page numbers with "Page X of Y" format.
 *
 * Uses react-pdf's render prop to access pageNumber and totalPages dynamically.
 * Can be placed inside PageFooter or anywhere in a Page, and supports the `fixed`
 * prop to repeat on every page.
 *
 * @example Basic usage (centered, on every page)
 * ```tsx
 * <Page>
 *   <View style={{ position: 'absolute', bottom: 20, left: 0, right: 0 }}>
 *     <PdfPageNumber fixed />
 *   </View>
 *   {content}
 * </Page>
 * ```
 *
 * @example Custom format
 * ```tsx
 * <PdfPageNumber format="{page} / {total}" align="right" />
 * ```
 *
 * @example Inside a PageFooter (recommended pattern)
 * ```tsx
 * <PageFooter variant="centered">
 *   <PdfPageNumber format="- {page} -" />
 * </PageFooter>
 * ```
 */
export function PdfPageNumber({
  format = 'Page {page} of {total}',
  align = 'center',
  size = 'sm',
  fixed = false,
  muted = true,
  style,
}: PdfPageNumberProps) {
  const theme = usePdfxTheme();
  const styles = useSafeMemo(() => createPageNumberStyles(theme), [theme]);

  const alignMap: Record<PageNumberAlign, Style> = {
    left: styles.alignLeft,
    center: styles.alignCenter,
    right: styles.alignRight,
  };

  const sizeMap: Record<PageNumberSize, Style> = {
    xs: styles.sizeXs,
    sm: styles.sizeSm,
    md: styles.sizeMd,
  };

  const textStyles: Style[] = [
    styles.text,
    alignMap[align],
    sizeMap[size],
    muted ? styles.colorMuted : styles.colorForeground,
  ];

  if (style) {
    textStyles.push(style);
  }

  return (
    <View style={styles.container} fixed={fixed}>
      <PDFText
        style={textStyles}
        render={({ pageNumber, totalPages }) => formatPageNumber(format, pageNumber, totalPages)}
      />
    </View>
  );
}

import { StyleSheet } from '@react-pdf/renderer';
import { usePdfxTheme } from '../lib/pdfx-theme-context';
type PdfxTheme = ReturnType<typeof usePdfxTheme>;

export function createPageNumberStyles(theme: PdfxTheme) {
  const { typography, colors, primitives } = theme;

  return StyleSheet.create({
    container: {
      width: '100%',
    },
    text: {
      fontFamily: typography.body.fontFamily,
    },
    // Alignment variants
    alignLeft: {
      textAlign: 'left',
    },
    alignCenter: {
      textAlign: 'center',
    },
    alignRight: {
      textAlign: 'right',
    },
    // Size variants
    sizeXs: {
      fontSize: primitives.typography.xs,
    },
    sizeSm: {
      fontSize: primitives.typography.sm,
    },
    sizeMd: {
      fontSize: primitives.typography.base,
    },
    // Color variants
    colorForeground: {
      color: colors.foreground,
    },
    colorMuted: {
      color: colors.mutedForeground,
    },
  });
}

/**
 * Text alignment for the page number.
 */
export type PageNumberAlign = 'left' | 'center' | 'right';

/**
 * Size preset for the page number text.
 */
export type PageNumberSize = 'xs' | 'sm' | 'md';

/**
 * Props for the PdfPageNumber component.
 */
export interface PdfPageNumberProps {
  /** Custom styles to merge with component defaults */
  style?: Style;
  /**
   * Format string for the page number.
   * Use `{page}` for current page and `{total}` for total pages.
   * @default "Page {page} of {total}"
   * @example "Page {page} of {total}"
   * @example "{page} / {total}"
   * @example "- {page} -"
   */
  format?: string;

  /**
   * Text alignment.
   * @default "center"
   */
  align?: PageNumberAlign;

  /**
   * Size preset for the text.
   * @default "sm"
   */
  size?: PageNumberSize;

  /**
   * Whether the page number should be fixed (appear on every page).
   * Use this when placing inside a Page component to repeat on all pages.
   * @default false
   */
  fixed?: boolean;

  /**
   * Use muted color (mutedForeground) instead of foreground.
   * @default true
   */
  muted?: boolean;

  /**
   * No children allowed.
   */
  children?: never;
}
